import logging
import os
from azure.storage.blob import BlobServiceClient
from azure.cosmosdb.table.tableservice import TableService
from azure.eventgrid import EventGridPublisherClient

def main(mytimer: func.TimerRequest) -> None:
    # Get the storage and cosmos db connection strings from environment variables
    storage_connection_string = os.environ['STORAGE_CONNECTION_STRING']
    cosmosdb_connection_string = os.environ['COSMOSDB_CONNECTION_STRING']

    # Create blob service client
    blob_service_client = BlobServiceClient.from_connection_string(storage_connection_string)

    # Get the list of blobs from the storage account
    blobs = blob_service_client.list_blobs()

    # Loop through each blob and process it
    for blob in blobs:
        # Download the blob to a local file
        with open(blob.name, 'wb') as f:
            f.write(blob.download_blob().readall())

        # Process the file and write results to cosmos db
        table_service = TableService(cosmosdb_connection_string)
        table_service.insert_entity('mytable', {'id': blob.name, 'data': 'processed'})

        # Send a notification via event grid
        event_grid_publisher_client = EventGridPublisherClient(cosmosdb_connection_string)
        event_grid_publisher_client.send_event('mytopic', {'id': blob.name, 'data': 'processed'})